// Angular: toggle aria-expanded and hidden together
@Component({
  template: `
    <button [attr.aria-expanded]="open"
            [attr.aria-controls]="'faq-' + id + '-content'"
            (click)="toggle()">
      {{ question }}
    </button>
    <div [id]="'faq-' + id + '-content'"
         role="region"
         [attr.aria-labelledby]="'faq-' + id"
         [hidden]="!open">
      {{ answer }}
    </div>
  `,
})
export class FaqItemComponent {
  @Input() id!: string;
  @Input() question!: string;
  @Input() answer!: string;
  open = false;
  toggle() { this.open = !this.open; }
}

// Angular: update a live region reactively
@Component({
  template: `
    <p role="status" aria-live="polite" aria-atomic="true">
      {{ statusMessage() }}
    </p>
  `,
})
export class SearchResultsComponent {
  statusMessage = signal('');
  results = signal<Item[]>([]);

  onSearch(query: string): void {
    // Update status AFTER results render, so the announcement includes count
    this.results.set(this.searchService.search(query));
    this.statusMessage.set(\`\${this.results().length} results for "\${query}"\`);
  }
}

