import { LiveAnnouncer } from '@angular/cdk/a11y';
import { AriaDescriber } from '@angular/cdk/a11y';

import { Component, inject } from '@angular/core';
import { LiveAnnouncer } from '@angular/cdk/a11y';

@Component({
  selector: 'app-file-upload',
  standalone: true,
  template: `
    <input type="file" (change)="onFile($event)" />
    <button (click)="upload()">Upload</button>
  `,
})
export class FileUploadComponent {
  private announcer = inject(LiveAnnouncer);

  async upload(): Promise<void> {
    await this.uploadService.upload(this.file);

    // Announce success to screen readers without changing the visible DOM
    await this.announcer.announce('File uploaded successfully.', 'polite');
  }

  async onFile(event: Event): Promise<void> {
    const file = (event.target as HTMLInputElement).files?.[0];
    if (!file) return;
    this.file = file;
    await this.announcer.announce(\`Selected \${file.name}\`, 'polite');
  }
}
